/**
 * Full Onboarding E2E Flow Tests
 *
 * Tests the complete user journey from landing page through
 * KYC/KYB verification, survey, wallet connect, and subscription.
 *
 * These tests run against a LIVE dev server (no mocks).
 * Email verification steps require manual intervention or are paused.
 */
import { test, expect } from '@playwright/test'
import { KycFormPage } from './pages/kyc-form-page-object'
import { KybFormPage, KYB_ENTITY_INFO, KYB_LEGAL_REP } from './pages/kyb-form-page-object'
import { nextTestEmail } from './helpers/auto-increment-email-suffix'
import { answerSurveyFlow } from './helpers/survey-answer-helper'

// Generate unique emails per run (+DDMMYY0X auto-increments)
const kycEmail = nextTestEmail()
const kybEmail = nextTestEmail()

// Test data for KYC flow
const KYC_USER = {
  firstName: 'Phong',
  lastName: 'Retzka',
  email: kycEmail,
  password: 'Granit#34Xhaka',
  repeatPassword: 'Granit#34Xhaka',
  dateOfBirth: { day: '15', month: '06', year: '1990' },
}

const KYC_ADDRESS = {
  street: '123 Main Street',
  city: 'New York',
  stateRegion: 'NY',
  zipCode: '10001',
  country: 'United States',
  countryCode: 'USA',
}

// Test data for KYB flow
const KYB_USER = {
  email: kybEmail,
  password: 'Granit#34Xhaka',
  confirmPassword: 'Granit#34Xhaka',
}

test.describe('Full KYC Onboarding Flow (Individual)', () => {
  test('should complete KYC from landing to dashboard', async ({ page }) => {
    // Step 1: Navigate to landing page
    await page.goto('/en')
    await expect(page).toHaveURL(/\/en/)
    await page.screenshot({ path: 'e2e/screenshots/01-landing.png' })

    // Step 2: Click Get Started to trigger auth flow
    const getStartedButton = page.getByRole('link', { name: /get started/i }).first()
    await getStartedButton.click()
    await page.waitForURL(/\/(auth|onboarding)/, { timeout: 30000 })
    await page.screenshot({ path: 'e2e/screenshots/02-auth-choice.png' })

    // Step 2b: Navigate to starter type selection
    // If redirected to auth/choose, click Sign Up first
    if (page.url().includes('/auth/choose')) {
      const signUpLink = page.getByRole('link', { name: /sign up/i })
      if (await signUpLink.isVisible()) {
        await signUpLink.click()
        await page.waitForURL(/\/(sign-up|onboarding)/, { timeout: 30000 })
      }
    }

    // Navigate to starter type if not already there
    if (!page.url().includes('/onboarding/starter-type')) {
      await page.goto('/en/onboarding/starter-type')
    }
    await page.waitForURL(/\/onboarding\/starter-type/)
    await page.screenshot({ path: 'e2e/screenshots/03-starter-type.png' })

    // Step 3: Choose "Individual" (KYC)
    const individualOption = page.getByText(/individual/i).first()
    await individualOption.click()

    const continueBtn = page.getByRole('button', { name: /continue/i })
    await continueBtn.click()
    await page.waitForURL(/\/kyc/, { timeout: 30000 })
    await page.screenshot({ path: 'e2e/screenshots/04-kyc-step1.png' })

    // Step 3.1.1: Fill KYC personal info form
    const kycForm = new KycFormPage(page)
    await kycForm.fillPersonalInfo(KYC_USER)
    await kycForm.fillDateOfBirth(
      KYC_USER.dateOfBirth.day,
      KYC_USER.dateOfBirth.month,
      KYC_USER.dateOfBirth.year
    )
    await page.screenshot({ path: 'e2e/screenshots/05-kyc-step1-filled.png' })
    await kycForm.submitPersonalInfo()

    // Step 3.1.2: Fill address form (step 2)
    await kycForm.street.waitFor({ state: 'visible', timeout: 10000 })
    await page.screenshot({ path: 'e2e/screenshots/06-kyc-step2.png' })
    await kycForm.fillAddress(KYC_ADDRESS)
    await kycForm.acceptAllTerms()
    await page.screenshot({ path: 'e2e/screenshots/07-kyc-step2-filled.png' })
    await kycForm.submitAddress()

    // Step 3.1.3: OTP verification screen
    await page.screenshot({ path: 'e2e/screenshots/08-kyc-otp.png' })

    // Pause here for manual email check — user needs to enter OTP
    // In CI, this would use an email API to fetch the code
    console.log('\n========================================')
    console.log('ACTION REQUIRED: Check email for OTP code')
    console.log(`Email: ${KYC_USER.email}`)
    console.log('Enter the OTP in the browser, then press Enter to continue...')
    console.log('========================================\n')
    await page.pause()

    // Step 3.1.4: After OTP verification, wait for KYC approval
    await page.screenshot({ path: 'e2e/screenshots/09-kyc-waiting.png' })

    // Wait for redirect to survey (may take time for KYC processing)
    console.log('Waiting for KYC approval and redirect to survey...')
    console.log('Press Enter in terminal once redirected to survey.')
    await page.pause()

    // Step 4: Survey flow — answer all questions
    await answerSurveyFlow(page, 'kyc')
  })
})

test.describe('Full KYB Onboarding Flow (Legal Entity)', () => {
  test('should complete KYB from landing to admin approval', async ({ page }) => {
    // Step 1: Navigate to starter type
    await page.goto('/en/onboarding/starter-type')
    await page.waitForURL(/\/onboarding\/starter-type/)
    await page.screenshot({ path: 'e2e/screenshots/kyb-01-starter-type.png' })

    // Step 2: Choose "Legal Entity" (KYB)
    const legalEntityOption = page.getByText(/legal entity/i).first()
    await legalEntityOption.click()

    const continueBtn = page.getByRole('button', { name: /continue/i })
    await continueBtn.click()
    await page.waitForURL(/\/kyb/, { timeout: 30000 })
    await page.screenshot({ path: 'e2e/screenshots/kyb-02-step1.png' })

    // Step 3.2.1: Fill entity info (step 1)
    const kybForm = new KybFormPage(page)
    await kybForm.fillEntityInfo(KYB_ENTITY_INFO)
    await page.screenshot({ path: 'e2e/screenshots/kyb-03-step1-filled.png' })
    await kybForm.submitStep()

    // Step 3.2.2: Fill legal representative (step 2)
    await kybForm.legalRepName.waitFor({ state: 'visible', timeout: 10000 })
    await page.screenshot({ path: 'e2e/screenshots/kyb-04-step2.png' })
    await kybForm.fillLegalRep(KYB_LEGAL_REP)
    await page.screenshot({ path: 'e2e/screenshots/kyb-05-step2-filled.png' })
    await kybForm.submitStep()

    // Step 3.2.3: Upload documents (step 3)
    await page.waitForTimeout(2000) // Wait for upload form to render
    await page.screenshot({ path: 'e2e/screenshots/kyb-06-step3.png' })
    await kybForm.uploadDocuments()
    await page.screenshot({ path: 'e2e/screenshots/kyb-07-step3-uploaded.png' })
    await kybForm.submitStep()

    // Step 3.2.4: Fill credentials (step 4)
    await kybForm.email.waitFor({ state: 'visible', timeout: 10000 })
    await page.screenshot({ path: 'e2e/screenshots/kyb-08-step4.png' })
    await kybForm.fillCredentials(KYB_USER)
    await page.screenshot({ path: 'e2e/screenshots/kyb-09-step4-filled.png' })
    await kybForm.submitStep()

    // Step 3.2.5: Wait for admin approval
    await page.screenshot({ path: 'e2e/screenshots/kyb-10-waiting.png' })
    console.log('\n========================================')
    console.log('KYB submitted - waiting for admin approval')
    console.log(`Email: ${KYB_USER.email}`)
    console.log('Press Enter once admin approves and you reach survey.')
    console.log('========================================\n')
    await page.pause()

    // Step 4: Survey flow — answer all questions
    await answerSurveyFlow(page, 'kyb')
  })
})

import { defineConfig, devices } from '@playwright/test'

export default defineConfig({
  testDir: './e2e',
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: 'html',
  use: {
    baseURL: 'http://localhost:3816',
    trace: 'on-first-retry',
    screenshot: 'only-on-failure',
  },
  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
    {
      name: 'mobile',
      use: { ...devices['iPhone 14'] },
    },
  ],
})
